"""
MKT Context Commentary — Psalm 119 (all 176 verses)
Run: python3 scripts/zc-context-psalms-119-119.py

Key context decisions:
- Psalm 119 is a complete alphabetic acrostic: 22 stanzas × 8 verses,
  each stanza named for a successive Hebrew letter (Aleph–Taw). Every
  verse within a stanza begins with that letter. The form signals
  comprehensive totality — "from A to Z," the entire range of devotion.
- Eight Torah synonyms rotate through every stanza; their semantic
  distinctions are noted at first use. The overlapping vocabulary is not
  careless; the effect is a rich, multi-faceted portrait of divine instruction.
- Background: the Deuteronomic command to meditate on Torah day and night
  (Deut 6:6-9; Josh 1:8) is the psalm's presupposition throughout.
- Scribal/wisdom-piety tradition: the psalm reflects the Second Temple
  scribal ideal — the sage who has internalized Torah as both curriculum and
  way of life (cf. Ezra 7:10; Sirach 39:1-11).
- Honor-shame: the repeated fear of being "put to shame" (vv. 6, 31, 46,
  78, 80) reflects the honor-challenge dynamics of the ancient world; the
  petition is for YHWH-sponsored vindication in the community's eyes.
- The "stranger/sojourner" motif (vv. 19, 54) recalls the patriarchal
  pattern of dwelling without permanent land rights; Torah becomes the
  portable homeland.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "119": {
    "1": '<p><strong>Aleph stanza (vv. 1–8)</strong> — the opening letter of the Hebrew alphabet begins the psalm\'s comprehensive acrostic. Twenty-two stanzas, one per Hebrew letter, eight verses each — a total of 176 verses. The acrostic form communicates completeness and order; to go through the alphabet was to cover everything. No other biblical poem matches this scale. The form itself is a declaration: Torah devotion encompasses the whole of human existence, from aleph to taw.</p><p>The opening beatitude (<em>ʾašrê</em> = "how blessed") follows the Deuteronomic happiness-formula (cf. Deut 33:29; Ps 1:1): those who "walk without fault (<em>tāmîm</em>)" in YHWH\'s <em>tôrâ</em> (instruction/teaching) are declared blessed. <em>Tôrâ</em> — the broadest of the eight Torah synonyms — encompasses the entire instructional deposit of Sinai, not merely legal codes. The blessing is covenantal, not merely moral.</p>',
    "2": '<p>"Guard his <em>ʿēdôt</em> (testimonies/decrees)" — <em>ʿēdûtîm/ʿēdôt</em> derives from the root "to witness/attest"; they are the stipulations God witnesses to — most directly the tablets of the covenant kept in the Ark (<em>ʾărôn hāʿēdût</em> = Ark of the Testimony, Exod 25:16). Guarding his testimonies is covenantal fidelity to what YHWH has formally attested as his terms. "Pursue him with all their heart" — the whole-heart formula (<em>bĕkol-lēb</em>) is Deuteronomy\'s characteristic language (Deut 4:29; 6:5; 10:12); Torah devotion is not partial observance but total orientation.</p>',
    "3": '<p>"Who do nothing wrong but walk in his ways" — the two halves define negative (abstaining from wrong) and positive (active walking) faithfulness. "Walking (<em>hālaḵ</em>)" in YHWH\'s ways is the pervasive OT metaphor for covenant life as a continuous journey rather than a single decision. The "way" (<em>dereḵ</em>) as life-path is the Wisdom tradition\'s central metaphor (Prov 2:13-15; 3:17; 4:11) adopted here into the Torah-piety context.</p>',
    "4": '<p>"You have given your <em>piqqûdîm</em> (precepts) to be carefully obeyed (<em>lišmōr mĕʾōd</em>)" — <em>piqqûdîm</em> (H6490) derives from <em>pāqad</em> = to appoint, commission, charge; these are YHWH\'s specific charges entrusted to his people, requiring conscientious compliance (<em>mĕʾōd</em> = very much, with full effort). The word occurs only in Psalms (24 times in Ps 119 alone), suggesting it is specifically the language of the Torah-piety tradition rather than legal codes.</p>',
    "5": '<p>"How I wish my ways were truly set (<em>nākôn</em>) on keeping your <em>ḥuqqîm</em> (statutes)" — <em>ḥuqqîm/ḥuqqôt</em> (H2706/2708) derives from <em>ḥāqaq</em> = to inscribe/cut in stone; they are fixed, inscribed decrees — the permanent, non-negotiable terms. The aspiration expressed here (how I wish!) reflects the Deuteronomic awareness that Torah-keeping requires both divine instruction and divine enablement (cf. Deut 30:6 — "YHWH your God will circumcise your heart").</p>',
    "6": '<p>"Then I would not be shamed (<em>ʾēḇôš</em>) when I consider all your <em>miṣwôt</em> (commandments)" — shame (<em>bōšet</em>) in the ancient world was a public social catastrophe: being exposed as having failed one\'s obligations before one\'s community. The psalmist fears the shame of falling short of YHWH\'s <em>miṣwôt</em> (direct orders/commandments — from <em>ṣāwâ</em> = to command). The avoidance of shame motivates covenant faithfulness in an honor-shame culture.</p>',
    "7": '<p>"I will thank you with a sincere heart (<em>bĕyōšer lēḇāḇ</em>) as I learn your righteous <em>mišpāṭîm</em> (decrees)" — <em>mišpāṭîm</em> (H4941) = legal judgments/ordinances — the specific case-decisions and judicial rulings that constitute OT law. <em>Yōšer lēḇāḇ</em> = "uprightness of heart" — the interior sincerity that distinguishes genuine covenant loyalty from external compliance. The act of learning Torah naturally produces praise — the two are connected, not separated.</p>',
    "8": '<p>"I will keep your <em>ḥuqqîm</em> — please, LORD, do not abandon me (<em>ʿal-taʿazbēnî</em>)" — the stanza ends with a petition that reveals the theology underlying the whole psalm: Torah-keeping and divine presence are inseparable. "Do not abandon me (<em>ʿāzaḇ</em>)" is the language of covenant desertion (cf. Deut 31:6, 8 — YHWH promises not to abandon Israel). The psalmist\'s Torah-fidelity is offered as the ground for the petition, not as a merit-claim but as a covenant appeal.</p>',
    "9": '<p><strong>Beth stanza (vv. 9–16)</strong> — ב is the second letter; the stanza focuses on the "young man" (<em>naʿar</em>) keeping his life pure through Torah. This situates the psalm within the wisdom/educational tradition: the sage addressing youth (Prov 1:8; 3:1; 4:1; 7:1). In Second Temple Judaism, scribal education began with Torah memorization; the question "how can a young person keep their way pure?" was the curriculum question of every <em>bêt midrāš</em> (house of study). Torah was the answer to youthful moral vulnerability.</p>',
    "10": '<p>"With all my heart I have pursued you (<em>dĕrašttîḵā</em>)" — <em>dāraš</em> = to seek with urgency, to investigate (the term for studying Torah: <em>midrash</em> derives from it). The whole-heart pursuit of YHWH through Torah study is the Second Temple scribal ideal — Ezra "devoted himself to study (<em>liḏrōš</em>) the law of the LORD and to do it and to teach" (Ezra 7:10). "Do not let me drift from your <em>miṣwôt</em>" — despite the wholehearted pursuit, the psalmist knows drifting is possible; the petition acknowledges human fragility.</p>',
    "11": '<p>"I have treasured (<em>ṣāpantî</em>) your word in my heart so I will not sin against you" — <em>ṣāpan</em> = to hide, store, treasure (like storing valuables in a safe place). The internalizing of Torah in the "heart" (<em>lēḇ</em> = the center of intellect and will) is the Deuteronomic ideal: "these words... shall be on your heart" (Deut 6:6). This verse became foundational for Jewish Torah internalization theology and for NT understandings of the new covenant (Jer 31:33: "I will put my law within them and write it on their hearts").</p>',
    "12": '<p>"Blessed are you, O LORD — teach me your <em>ḥuqqîm</em>" — the liturgical blessing formula (<em>bārûḵ ʾattâ YHWH</em>) is the opening of the standard Jewish prayer blessing (<em>berakah</em>), still used in Jewish liturgy today. The petition "teach me" (<em>lammĕdēnî</em>) reframes Torah-keeping as divine teaching rather than mere human discipline; YHWH is the teacher, not just the lawgiver. This teacher-student framing runs throughout the psalm.</p>',
    "13": '<p>"With my lips I have declared all the <em>mišpāṭîm</em> that have come from your mouth" — oral recitation of Torah was the primary mode of transmission in ancient Israel and Second Temple Judaism. The Torah was spoken aloud (Deut 6:7: "recite them to your children, when you sit in your house and when you walk along the road"). The psalmist\'s "declaring with the lips" reflects this practice; written study was secondary to oral repetition in a predominantly oral culture.</p>',
    "14": '<p>"I rejoice in the path of your <em>ʿēdôt</em> as much as in every kind of wealth (<em>hôn</em>)" — <em>hôn</em> = wealth, property (Prov 13:11; 28:22). The comparison to wealth is the Wisdom tradition\'s standard measure of Torah\'s worth: Prov 3:14-15 ("she is more precious than jewels, and nothing you desire can compare with her"); Ps 19:10 ("more to be desired than gold, even much fine gold"). Torah is the supreme treasure in the ancient wisdom tradition.</p>',
    "15": '<p>"I will reflect (<em>ʾāśîaḥ</em>) on your <em>piqqûdîm</em> and keep my eyes on your paths" — <em>śîaḥ</em> (H7878) = to meditate, muse, reflect (the same verb in Ps 77:12; 143:5); it denotes the sustained inner rumination that is deeper than surface reading. The command to "meditate on this book of the law day and night" (Josh 1:8) uses the same verb. Torah meditation as a continuous, absorptive mental practice was the ideal for both the king (Deut 17:19) and every Israelite.</p>',
    "16": '<p>"I will delight in your <em>ḥuqqîm</em> — I will not forget (<em>ʾeškaḥ</em>) your word" — the fear of forgetting Torah is a Deuteronomic theme: "be careful that you do not forget the LORD your God, failing to keep his commandments, his <em>mišpāṭîm</em>, and his <em>ḥuqqîm</em>" (Deut 8:11). Forgetting (<em>šāḵaḥ</em>) in the covenantal sense is not mere memory failure but abandonment of relationship — the practical atheism of Ps 10:4. Delight (<em>šāʿaʿ</em>) is the antidote to forgetting.</p>',
    "17": '<p><strong>Gimel stanza (vv. 17–24)</strong> — ג introduces the motif of the psalmist as stranger/pilgrim. "Be generous (<em>gĕmōl</em>) with your servant that I may live" — <em>gāmal</em> = to deal bountifully, to complete/repay a kindness; the psalmist appeals to YHWH\'s covenant generosity (<em>ḥesed</em>) rather than personal merit. "Servant (<em>ʿeḇed</em>)" throughout this psalm is the formal covenant address of a subordinate to a sovereign — the diplomatic register appropriate for treaty-petition.</p>',
    "18": '<p>"Open my eyes (<em>gal-ʿênay</em>) to see the wonderful truths (<em>niplāʾôt</em>) in your <em>tôrâ</em>" — <em>niplāʾôt</em> = wonders, extraordinary things (the word used for the plagues of Egypt and acts of divine deliverance). The prayer treats Torah as a text containing hidden wonders accessible only through divinely opened eyes. This is the presupposition of rabbinic <em>midrash</em>: the text contains inexhaustible depth, and the reader needs supernatural illumination to perceive it.</p>',
    "19": '<p>"I am a foreigner (<em>gēr</em>) on this earth — do not hide your <em>miṣwôt</em> from me" — <em>gēr</em> (H1616) = resident alien, sojourner without full land rights. The <em>gēr</em> was a socially vulnerable person in ancient Israel — protected by law (Lev 19:33-34) but lacking the landed inheritance that defined full Israelite identity. The psalmist adopts this self-description as a theological stance: this world is not our permanent home (cf. 1 Chr 29:15; Heb 11:13). For the sojourner, YHWH\'s Torah replaces the land as orientation.</p>',
    "20": '<p>"My soul is worn out (<em>gārĕsâ</em>) with longing for your <em>mišpāṭîm</em> at every moment" — the language of physical exhaustion (<em>gāras</em> = to crush, grind) applied to spiritual yearning is strong: the desire for divine instruction is so intense it is physically consuming. <em>Bĕḵol-ʿēt</em> = "at every moment" — not merely daily or weekly Torah engagement but a continuous, unrelenting longing. This level of Torah-hunger was the scribal ideal.</p>',
    "21": '<p>"You rebuke the arrogant (<em>zēdîm</em>) — those who are cursed — who drift from your <em>miṣwôt</em>" — <em>zēdîm</em> (H2086) = the proud, arrogant; a category that appears repeatedly in this psalm as the psalmist\'s opponents (vv. 51, 69, 78, 85, 122). In the context of Second Temple Judaism, the "arrogant" likely includes both the powerful who enforce compliance with alternative practices and those who treat Torah observance with contempt. The "curse" upon them is the covenant curse of Deut 27-28.</p>',
    "22": '<p>"Take away the scorn (<em>ḥerpâ</em>) and contempt (<em>bûz</em>) that fall on me, for I have kept your <em>ʿēdôt</em>" — <em>ḥerpâ</em> = reproach/scorn (what opponents throw publicly to damage honor); <em>bûz</em> = contempt, treating someone as worthless. In honor-shame culture, these were serious social wounds — not merely personal feelings. The appeal to YHWH to "take away" (<em>gal</em>) the scorn is a petition for vindication in the community, a restoration of damaged honor through divine action.</p>',
    "23": '<p>"Even when rulers (<em>śārîm</em>) sit together plotting against me, your servant reflects on your <em>ḥuqqîm</em>" — the reference to rulers plotting implies a setting of political persecution or at least social opposition from those in power. In Second Temple contexts, this could reflect conflict between Torah-observant Jews and accommodating elites under Persian or Hellenistic rule. The psalmist\'s response is not political resistance but intensified Torah meditation — the <em>ḥuqqîm</em> are the psalmist\'s resource against power.</p>',
    "24": '<p>"Your <em>ʿēdôt</em> are my delight — they are my counselors (<em>ʾanšê ʿăṣātî</em>)" — the personification of Torah as a council of advisors is striking. <em>ʾAnšê ʿăṣātî</em> = "men of my counsel" — the royal court metaphor applied to Torah: just as a king surrounds himself with advisors, the psalmist\'s "court" is composed of Torah testimonies. This contrasts with the plotting rulers of v. 23; the psalmist has a better counsel than the political elite.</p>',
    "25": '<p><strong>Daleth stanza (vv. 25–32)</strong> — ד introduces deep lament: "My soul is brought low to the dust (<em>dāḇĕqâ lĕʿāpār napšî</em>)" — <em>dāḇaq</em> = to cling, stick to (the covenant-loyalty word in Gen 2:24 and Deut 4:4; 10:20); <em>ʿāpār</em> = dust (the stuff of mortality and humiliation — Gen 3:19; Job 2:12 — sitting in dust is the posture of mourning). The soul that should "cling" to YHWH (Deut 4:4) is clinging to the dust instead — the inversion of covenant orientation. The petition is for resurrection from prostration.</p>',
    "26": '<p>"I laid out my ways before you and you listened (<em>wattaʿănēnî</em>) — now teach me your <em>ḥuqqîm</em>" — the genre of laying out (<em>sippurtî</em>) one\'s ways before YHWH is confessional review, a practice associated with the penitential psalms (cf. Ps 32, 51). YHWH\'s listening validates the practice. The transition from confession ("you listened") to petition ("teach me") models the movement from lament to learning — suffering creates receptivity to instruction.</p>',
    "27": '<p>"Help me understand (<em>hăḇînēnî</em>) the path of your <em>piqqûdîm</em>, and I will ponder your wonderful deeds" — <em>bîn</em> (hiphil: to cause to understand, to give discernment) is the language of wisdom education. Understanding Torah is not self-generated; it requires divine enablement. <em>Niplāʾôt</em> (wonderful deeds) — as in v. 18, the psalmist perceives Torah not as mere rules but as wondrous divine acts (cf. Ps 78:1-8 where Torah and wonderful deeds are intertwined).</p>',
    "28": '<p>"My soul dissolves in grief (<em>dālĕpâ napšî mittûgâ</em>) — lift me up (<em>haqqîmēnî</em>) according to your word" — <em>dālap̄</em> = to drip, weep, melt (as wax); the image of a soul literally melting under the weight of grief. <em>Haqqîmēnî</em> = "raise me up, cause me to stand" — the hiphil of <em>qûm</em>, the resurrection-vocabulary word (same root: standing up from being brought low). Grief is the context; divine word is the means of being raised.</p>',
    "29": '<p>"Keep me from (<em>dereḵ-šeqer</em>) every path of falsehood and mercifully give me your <em>tôrâ</em>" — <em>šeqer</em> (H8267) = falsehood, deception, lying (the opposite of <em>ʾemet</em>, truth). The "path of falsehood" is not merely dishonesty but an alternative way of life — a false orientation toward reality as opposed to the true path of Torah. The petition for Torah as the antidote to šeqer reflects the wisdom tradition: false paths lead to death; Torah\'s path leads to life (Prov 12:17-19).</p>',
    "30": '<p>"I have chosen (<em>bāḥartî</em>) the path of truth and set your <em>mišpāṭîm</em> before me" — <em>bāḥar</em> = to choose deliberately (the Deuteronomic election-word: "choose life," Deut 30:19). The psalmist frames Torah-keeping as a deliberate act of choosing, not merely inherited practice or social pressure. "Setting before me (<em>šiwwîtî</em>)" = the same word as Ps 16:8 ("I keep my eyes always on the LORD") — the act of holding something constantly in view as the orienting reference point.</p>',
    "31": '<p>"I have clung (<em>dāḇaqtî</em>) to your <em>ʿēdôt</em>, O LORD — do not let me be put to shame (<em>ʾal-tĕḇîšēnî</em>)" — <em>dāḇaq</em> (to cling) appears again from v. 25; the soul that had been clinging to dust now clings to Torah-testimonies instead. The honor-shame petition ("do not shame me") grounds the appeal in YHWH\'s covenant obligation: a covenant lord who vindicates his loyal servant maintains his own honor as patron. The psalmist\'s loyalty grounds the petition.</p>',
    "32": '<p>"I will run (<em>ʾārûṣ</em>) the path of your <em>miṣwôt</em> when you set my heart free (<em>tarbîb libbî</em>)" — "running" the path of Torah (not merely walking) is a metaphor for eager, energetic faithfulness rather than grudging compliance. <em>Tarbîb libbî</em> = "when you enlarge my heart" — the enlargement of the heart is a metaphor for the expansion of moral and spiritual capacity; YHWH\'s gift of a "large heart" enables joyful Torah-keeping. Contrast the hardened hearts of the opponents (vv. 70, 85).</p>',
    "33": '<p><strong>He stanza (vv. 33–40)</strong> — ה (He) is the stanza of teaching petitions: every verse is a petition for divine instruction ("teach me," "grant me," "guide me," "turn my heart"). The concentration of teaching petitions in this stanza is unmatched in the psalm. The background is Deut 4:1 ("hear the statutes and ordinances I am teaching you") and Deut 6:1 ("these are the commandments... the LORD your God commanded me to teach you"). YHWH is the ultimate teacher; the human teacher mediates his instruction.</p>',
    "34": '<p>"Grant me understanding (<em>hăḇînēnî</em>) to keep your <em>tôrâ</em> and obey it with all my heart" — <em>bîn</em> again: understanding Torah requires divine illumination. The combination of understanding + all-heart obedience is the Shema\'s pattern (Deut 6:4-9): love of YHWH with all the heart, soul, and strength is expressed through Torah-keeping. The petition collapses the distinction between comprehension and obedience: genuine understanding produces whole-hearted compliance.</p>',
    "35": '<p>"Guide me along the path (<em>naʿănî bĕnetîḇ miṣwôtêkā</em>) of your <em>miṣwôt</em> — that is where my delight is" — <em>nāhal</em> = to lead to a watering place (Ps 23:2 — "he leads me beside still waters"). The pastoral imagery of being led along a path resonates with the shepherd-and-sheep tradition; Torah-keeping is not self-directed navigation but following where YHWH leads. Delight (<em>ḥāpāṣtî</em>) = taking pleasure in; the commanded path is the preferred path.</p>',
    "36": '<p>"Turn (<em>haṭ</em>) my heart toward your <em>ʿēdôt</em> and away from selfish gain (<em>beṣaʿ</em>)" — <em>beṣaʿ</em> (H1215) = unjust gain, profit through exploitation (the word used in Exod 18:21 for corrupt judges and in Isa 56:11 for greedy religious leaders). The petition to have the heart "turned away" from <em>beṣaʿ</em> reveals the psalmist\'s awareness that the primary competition for covenant loyalty is not paganism but economic self-interest — the covetousness that the Decalogue prohibits last.</p>',
    "37": '<p>"Turn my eyes away from worthless things (<em>šāwĕʾ</em>)" — <em>šāwĕʾ</em> (H7723) = emptiness, vanity, worthlessness (the same word as the third commandment: "do not take the name of the LORD your God in vain"). The "worthless things" that attract the eyes are the idols, luxuries, and false securities of the surrounding culture. The petition for averted eyes is a petition for single-visioned focus — the wisdom tradition\'s ideal of the person whose eyes are set on one goal (Prov 4:25).</p>',
    "38": '<p>"Fulfill your promise (<em>qiyyēm ʾimrātĕkā</em>) to your servant — the promise given to those who revere you" — <em>ʾimrâ</em> (H565) = word, saying, promise — a more intimate, relational term than <em>dāḇār</em>; it carries the nuance of a personal pledge. "Those who fear you (<em>lĕyirʾātêkā</em>)" is a Second Temple technical term for the community of the pious who maintain Torah-reverence in the face of opposition (cf. Mal 3:16: "those who fear the LORD spoke to one another").</p>',
    "39": '<p>"Take away the shame I dread, for your <em>mišpāṭîm</em> are good" — the psalmist dreads a specific shame (<em>ḥerpātî ʾăšer yāgōrtî</em> = "the reproach I am dreading"). In the honor-shame culture, a person of Torah-devotion who suffered while the arrogant prospered was at risk of social shame — the public perception that their piety was misguided. The psalmist\'s appeal is that YHWH\'s <em>mišpāṭîm</em> are "good (<em>ṭôḇ</em>)" — even if that goodness is not yet publicly visible.</p>',
    "40": '<p>"See how I long for your <em>piqqûdîm</em> — give me life through your righteousness (<em>bĕṣidqātĕkā</em>)" — <em>ṣĕdāqâ</em> (righteousness) as the basis for life is a Deutero-Isaiah emphasis (Isa 46:13; 51:5-8): YHWH\'s righteousness is his covenant faithfulness, his commitment to deliver his people. Life (<em>ḥayyîm</em>) is not merely biological survival but the full, oriented life of covenant relationship. The petition connects physical renewal with covenantal restoration.</p>',
    "41": '<p><strong>Vav stanza (vv. 41–48)</strong> — ו (Vav = "and/hook") opens the stanza of steadfast love and bold public witness. "Let your <em>ḥesed</em> come to me, LORD — your salvation just as you have promised" — <em>ḥesed</em> (covenant loyalty/steadfast love) is the foundational attribute of YHWH (Exod 34:6-7); it is his commitment to his covenant partner regardless of the partner\'s failure. The psalmist appeals to <em>ḥesed</em> rather than merit — the proper ground of any OT petition for divine help.</p>',
    "42": '<p>"So I will have a reply (<em>ʾeʿĕnê</em>) for those who mock me, because I trust in your word" — the social context of ridicule (<em>ḥōrĕpî</em> = those who reproach/taunt) is the background. The psalmist\'s trust in YHWH\'s word (<em>dāḇār</em>) is both the target of the mockery ("where is your God?") and the source of the answer. In honor-shame culture, having a compelling response to taunt was itself a form of social vindication.</p>',
    "43": '<p>"Do not let me lose the power to speak truth (<em>ʾal-taṣṣēl mippî dĕḇar-ʾemet</em>), for my hope is in your <em>mišpāṭîm</em>" — "the word of truth" (<em>dĕḇar-ʾemet</em>) is the content of the psalmist\'s hoped-for public testimony. The fear that it might be "snatched away" (<em>nāṣal</em>) suggests the psalmist may be in a situation where external pressure (political or social) could force silence. Torah-based speech in the face of opposition is the Second Temple martyr-ideal.</p>',
    "44": '<p>"I will keep your <em>tôrâ</em> at all times, forever and ever (<em>lĕʿôlām wāʿed</em>)" — the temporal formula "forever and ever" is covenantal: the eternal Torah (cf. Ps 119:89 — "your word stands firm forever in the heavens") requires eternal keeping. The psalmist\'s vow of perpetual Torah-keeping mirrors the eternal nature of what is being kept — a fitting response to an eternal covenant.</p>',
    "45": '<p>"I will move freely (<em>ʾethallēḵâ bāmĕrḥāḇ</em>), for I have sought out your <em>piqqûdîm</em>" — <em>mĕrḥāḇ</em> = broad, spacious place (the opposite of the narrow straits of crisis — cf. Ps 4:1; 18:19). Freedom of movement in the ancient world was itself a social and political privilege — slaves and debtors had constrained movement; free citizens moved freely. The psalmist\'s Torah-keeping is the source of existential freedom rather than constraint. This directly counters the assumption that law is constricting.</p>',
    "46": '<p>"I will speak of your <em>ʿēdôt</em> before kings (<em>mĕlākîm</em>) and will not be ashamed (<em>wĕlōʾ ʾēḇôš</em>)" — testimony before kings was the rarest and most dangerous form of public speech in the ancient world. Kings had absolute power to silence, punish, or execute. The psalmist\'s declaration of fearlessness echoes the prophetic tradition (Elijah before Ahab; Jeremiah before Zedekiah). This verse became a resource for later martyrdom theology.</p>',
    "47": '<p>"I will find my delight (<em>ʾešteʿăšāʿ</em>) in your <em>miṣwôt</em>, which I love" — the rare intensive form <em>šāʿaʿ</em> (to delight excessively, to be absorbed in) appears: the psalmist does not merely observe the commandments but is enchanted by them. The commandments are the object of love (<em>ʾāhēḇ</em>), not just obedience. The Wisdom tradition\'s love of wisdom (Prov 4:6, 8; 8:17) is here transferred to Torah itself.</p>',
    "48": '<p>"I will reach out toward (<em>ʾeśśāʾ-kappay</em>) your <em>miṣwôt</em>, which I love, and reflect on your <em>ḥuqqîm</em>" — <em>nāśāʾ kappayim</em> = "to lift the palms/hands" — the gesture of worship and prayer (v. 48 applies a prayer gesture to the commandments themselves: the psalmist worships through Torah). Lifting hands toward the commandments, as toward a sanctuary, completes the stanza\'s movement from petition to bold witness to contemplative devotion.</p>',
    "49": '<p><strong>Zayin stanza (vv. 49–56)</strong> — ז (Zayin) is the stanza of memory and comfort in suffering. "Remember (<em>zĕḵōr</em>) the word you gave to your servant — the word that gave me hope" — the petition "remember" (<em>zāḵar</em>) is addressed to YHWH, not the psalmist; it invokes the covenant practice of divine remembering (Gen 9:15-16; Exod 2:24; Lev 26:42-45). YHWH\'s "remembering" in the OT is not cognitive recollection but active covenant-faithful intervention.</p>',
    "50": '<p>"This is what comforts me when I suffer: your word has kept me alive (<em>dĕḇārĕkā ḥiyyātanî</em>)" — the life-giving power of YHWH\'s word is a Deuteronomic claim: "one does not live by bread alone, but by every word that comes from the mouth of God" (Deut 8:3, cited by Jesus in Matt 4:4). Torah as literally life-sustaining — not merely instructive but vitalizing — is the experiential claim of this verse.</p>',
    "51": '<p>"The proud (<em>zēdîm</em>) have made fun of me at every turn, yet I have not swerved from your <em>tôrâ</em>" — ridicule as a form of social pressure is a recurring motif in this psalm (cf. v. 22, 42). The <em>zēdîm</em> (arrogant ones) mock Torah-piety as naive or socially counterproductive. The psalmist\'s response is not argument but perseverance — the "not swerving" despite mockery is the mark of genuine covenant loyalty vs. social-pressure compliance.</p>',
    "52": '<p>"I call to mind (<em>zāḵartî</em>) your ancient <em>mišpāṭîm</em>, O LORD, and find comfort in them" — <em>mišpāṭîm</em> described as "ancient" (<em>mēʿôlām</em>) grounds them in the cosmic order: YHWH\'s judicial decisions are not recent innovations but primordial realities. Recalling past divine judgments (the Exodus, the conquest, the returns from exile) provides comfort in present distress — the historical memory of YHWH\'s interventions is itself consolation.</p>',
    "53": '<p>"Rage and anguish (<em>zălʿāpâ</em>) grip me when I see the wicked forsaking your <em>tôrâ</em>" — <em>zălʿāpâ</em> (H2152) = burning heat, rage/anguish (used of the sirocco wind and of terror). The psalmist\'s emotional response to Torah-violation is visceral: not merely disapproval but burning indignation. The prophetic tradition modeled this: Phinehas\'s "zeal" (Num 25:11-13; cf. Ps 69:9 — "zeal for your house has consumed me"). Righteous zeal for Torah-observance is a covenantal virtue.</p>',
    "54": '<p>"Your <em>ḥuqqîm</em> have been the songs I sing in this place where I am passing through (<em>bêt mĕgûray</em>)" — <em>mĕgûr</em> = sojourning/temporary residence (cf. v. 19: <em>gēr</em> = sojourner). Life is a temporary dwelling (<em>bêt mĕgûray</em> = "the house of my wanderings") — the patriarchal pattern of dwelling in tents without permanent settlement (Heb 11:9-10). Torah <em>ḥuqqîm</em> as "songs" (<em>zĕmirôt</em>) suggests they were actually sung/chanted — consistent with the synagogue practice of Torah cantillation.</p>',
    "55": '<p>"I call your name to mind in the night (<em>ballaylâ</em>), O LORD, and keep your <em>tôrâ</em>" — night-time Torah meditation and prayer appears repeatedly in this psalm (vv. 55, 62, 147-148). The night watches (three watches in the OT: sunset, midnight, dawn) were the traditional time for prayer, watchfulness, and contemplation. Night prayer was practiced by priestly families (Ps 134:1), by the righteous (Ps 63:6), and became a feature of Second Temple piety and early Christian practice (Acts 16:25).</p>',
    "56": '<p>"This is what has been mine (<em>zōʾt hāyĕtâ-llî</em>) because I kept your <em>piqqûdîm</em>" — the verse summarizes the stanza\'s theme: the experience of divine comfort, the songs in the night, the calling on the name — all this is what the psalmist has "received/possessed" through Torah-keeping. The formulation is experiential rather than doctrinal: this is what I have personally received through Torah-fidelity.</p>',
    "57": '<p><strong>Kheth stanza (vv. 57–64)</strong> — ח (Kheth) opens with the Levitical theology of the portion: "The LORD is my portion (<em>ḥelqî YHWH</em>)" — <em>ḥēleq</em> = portion, share (the word used for the tribal land allotments in Joshua). The Levites famously received no territorial portion in Canaan (Num 18:20; Deut 10:9) — YHWH himself was their inheritance instead. The psalmist adopts this Levitical self-understanding: unlike the tribes who received land, the psalmist\'s "land" is YHWH himself. Torah-devotion is the Levitical vocation extended to all Israel.</p>',
    "58": '<p>"I have asked for your favor (<em>ḥillîtî pānêkā</em>) with all my heart — be gracious to me as you have promised" — <em>ḥillâ pānîm</em> = "to stroke the face of," a gesture of supplication adapted from the social custom of approaching a patron or superior by stroking or entreating their face as a mark of deference. The idiom appears in Exod 32:11; 1 Kgs 13:6; Zech 7:2 in contexts of urgent petition. The psalmist approaches YHWH with the same deferential posture.</p>',
    "59": '<p>"When I stopped to think about (<em>ḥiššaḇtî dĕrāḵāy</em>) my life, I turned my steps back to your <em>ʿēdôt</em>" — <em>ḥāšaḇ dĕrāḵîm</em> = "to reckon/consider one\'s ways" — the language of moral self-examination. The practice of reviewing one\'s conduct against the covenant standard was central to OT piety (cf. Lam 3:40: "let us examine our ways and test them, and let us return to the LORD"). The psalmist\'s self-examination leads to <em>tĕšûḇâ</em> (turning/returning).</p>',
    "60": '<p>"I was quick (<em>ḥaštî</em>) and did not hesitate to obey your <em>miṣwôt</em>" — urgency in covenant response is a Deuteronomic ideal: "be careful to obey... carefully follow all the commands" (Deut 5:32; 8:1). The psalmist\'s quick, unhesitating obedience contrasts with Israel\'s repeated pattern of delay and resistance. Speed of response reflects depth of devotion — the opposite of the Exodus generation\'s "stiff-necked" foot-dragging.</p>',
    "61": '<p>"The wicked have tried to trap me (<em>ḥeḇlê rĕšāʿîm ʿiwwĕtunî</em>), but I have not forgotten your <em>tôrâ</em>" — <em>ḥeḇālîm</em> = ropes, cords, snares; the image of being ensnared is a standard OT metaphor for wickedness\'s power to entrap (Prov 5:22; Ps 140:5). Despite the trapping attempt, the psalmist did not forget Torah — indicating that the temptation or pressure was specifically to abandon covenant practice, not merely abstract wickedness.</p>',
    "62": '<p>"I rise at midnight (<em>ḥăṣôt-laylâ</em>) to thank you for your righteous <em>mišpāṭîm</em>" — <em>ḥăṣôt</em> = midnight (the midpoint of the night). The midnight prayer is unusual enough to be distinctive: it signals extraordinary devotion beyond the normal prayer times (morning, noon, evening — Ps 55:17). The night watches and midnight prayer became characteristic practices in early monasticism; this verse was foundational for the tradition of the <em>vigilia</em>.</p>',
    "63": '<p>"I am a friend (<em>ḥāḇēr ʾănî</em>) to all who revere you and to all who keep your <em>piqqûdîm</em>" — <em>ḥāḇēr</em> = associate, fellow member of a guild or fellowship; in Second Temple Judaism, the <em>ḥăḇûrôt</em> (fellowship groups) were the voluntary associations of the devout who ate together in purity and maintained Torah observance together. The psalmist identifies with this social network — the community of the pious as the psalmist\'s primary social bond, superseding family or tribal ties.</p>',
    "64": '<p>"The earth is full of your <em>ḥesed</em>, O LORD — teach me your <em>ḥuqqîm</em>" — the observation that the whole earth is saturated with divine covenant loyalty provides the ground for the petition. If YHWH\'s <em>ḥesed</em> fills the earth, then directing some of it toward the psalmist in the form of Torah-instruction is a natural corollary. The cosmic scope of divine kindness becomes the basis for personal petition — no request is too small if the reservoir is infinite.</p>',
    "65": '<p><strong>Teth stanza (vv. 65–72)</strong> — ט (Teth), the letter of "good" (<em>ṭôḇ</em>) — the stanza returns to this word repeatedly. "You have been good (<em>ṭôḇ ʿāśîtā</em>) to your servant, LORD — just as you promised" — the theological affirmation of divine goodness grounds the entire stanza. YHWH\'s goodness is experienced through Torah-instruction, affliction, and discipline. The stanza\'s theology: suffering is a form of divine goodness.</p>',
    "66": '<p>"Teach me discernment (<em>ṭûb ṭaʿam waḏaʿat</em>) and understanding, for I trust in your <em>miṣwôt</em>" — <em>ṭûb ṭaʿam</em> = "good taste/discernment" — <em>ṭaʿam</em> is the word for taste (physical) and good judgment (intellectual): Abigail is described as having "good sense (<em>ṭôḇat śekel</em>)" (1 Sam 25:3). The request for moral discernment alongside cognitive understanding reflects the Wisdom tradition\'s integration of moral character and intellectual capacity as a single gift.</p>',
    "67": '<p>"Before I suffered (<em>bĕṭerem ʾeʿĕneh</em>) I used to wander; but now I keep your word" — the spiritual biography in this verse is compressed but powerful: pre-affliction wandering, affliction as turning point, post-affliction Torah-keeping. The pattern is replicated in Ps 107:17-22 (those who suffered because of their sin — then cried to YHWH). Suffering functions as a corrective in the Deuteronomic theology of discipline (Deut 8:2-5: "the LORD your God disciplined you as a parent disciplines their child").</p>',
    "68": '<p>"You are good (<em>ṭôḇ</em>) and you do what is good — teach me your <em>ḥuqqîm</em>" — the theological claim "God is good" is not a vague affirmation but a covenant assertion: YHWH\'s goodness is his covenant faithfulness expressed in specific acts of help and instruction. The request for teaching is itself an act of faith in divine goodness — to ask for Torah is to trust that YHWH is willing and able to give it.</p>',
    "69": '<p>"The arrogant (<em>zēdîm</em>) have spread lies (<em>ṭāplĕlû</em>) about me, but I will keep your <em>piqqûdîm</em> with all my heart" — <em>ṭāpal</em> (H2950) = to smear, plaster on (falsehood); the image of lies as something smeared over a surface (like whitewash — Ezek 13:10-12). The psalmist\'s opponents use false charges as a social weapon, but the response is not counter-accusation but intensified Torah-keeping. This is the Second Temple martyr-response: endure false accusation through covenantal fidelity.</p>',
    "70": '<p>"Their hearts are hardened and insensible (<em>ṭāpǎš kallāḇ libbām</em>), but I delight in your <em>tôrâ</em>" — <em>ṭāpǎš</em> (H2954) = to be fat, dull, insensible (a rare word; the heart that has become like fat = unresponsive to divine instruction). The hardened heart is the opposite of the circumcised heart promised in Deut 30:6 and Jer 31:33. The contrast is stark: their fattened hearts vs. the psalmist\'s delighted heart — two outcomes of the same exposure to Torah.</p>',
    "71": '<p>"My suffering was good for me (<em>ṭôḇ-lî kî-ʿunnêtî</em>), because it taught me your <em>ḥuqqîm</em>" — one of the most theologically dense verses in the psalm. The claim that suffering is "good" is not stoicism but covenantal experience: suffering became the context for divine instruction. The Deuteronomic theology of discipline (Deut 8:5; Prov 3:11-12; Heb 12:11) underlies this: YHWH\'s discipline through hardship is a form of parental love that produces Torah-wisdom.</p>',
    "72": '<p>"The <em>tôrâ</em> from your mouth is worth more to me than thousands of gold and silver coins" — the comparison to gold and silver is the Wisdom tradition\'s standard for wisdom\'s worth (Prov 3:14-15; 8:10-11, 19; 16:16; Job 28:15-19). The "thousands" (<em>ʾalpê</em>) = the maximum imaginable quantity of precious metal. Torah as surpassingly valuable is a direct counter to the <em>beṣaʿ</em> (unjust gain) of v. 36: the psalmist has found the true treasure that makes earthly wealth pale.</p>',
    "73": '<p><strong>Yod stanza (vv. 73–80)</strong> — י (Yod), the smallest Hebrew letter, opens a stanza of creation theology and social solidarity. "Your hands (<em>yādêkā</em>) made me and formed me (<em>kônĕnûnî</em>) — give me understanding to learn your <em>miṣwôt</em>" — <em>yāśar + kûn</em>: two verbs of divine craftsmanship. The appeal from creation: the creator who fashioned the creature is the same one who issues the commands; the creator is best suited to instruct the created, and the creation has an inherent obligation to learn from its maker.</p>',
    "74": '<p>"Those who revere you (<em>yĕrēʾêkā</em>) will see me and be glad, because I have put my hope in your word" — the community of the fearers-of-YHWH (<em>yĕrēʾê YHWH</em>) is a Second Temple technical term for the pious community (cf. Ps 22:23; 115:11; Mal 3:16). The psalmist\'s hoped-for vindication will be experienced as the community\'s own gladness — they share in the outcome of each member\'s faithfulness. Torah-piety is not private; it has a communal dimension.</p>',
    "75": '<p>"I know, O LORD, that your <em>mišpāṭîm</em> are right and that you disciplined (<em>ʿinnîtanî</em>) me out of faithfulness (<em>ʾĕmûnâ</em>)" — <em>ʾĕmûnâ</em> = faithfulness/reliability (the root of "Amen"). YHWH\'s faithfulness is expressed through discipline, not despite it. This is the Deuteronomic theology of the psalms: suffering is not the sign of divine abandonment but the evidence of ongoing covenant engagement. The one who suffers within the covenant relationship is still in the relationship.</p>',
    "76": '<p>"Let your <em>ḥesed</em> be a comfort (<em>nĕḥāmâ</em>) to me, just as you promised your servant" — <em>nĕḥāmâ</em> = comfort, consolation (the noun from <em>nāḥam</em> = to comfort; the name of the Comfort book, Nahum). YHWH\'s covenant loyalty (<em>ḥesed</em>) is the source of comfort because it is reliable: the consolation that comes from knowing that the covenant partner will not abandon. This is the ground of the "Comfort, comfort my people" of Isa 40:1.</p>',
    "77": '<p>"Let your compassion (<em>raḥămîm</em>) come to me so I may live — your <em>tôrâ</em> is my delight" — <em>raḥămîm</em> (H7356) = deep compassion, visceral tenderness (related to <em>reḥem</em> = womb); the most intimate of the divine emotional words, connoting mother-love (Isa 49:15). The appeal to divine womb-love is the most intimate possible ground for petition. Torah as "delight" alongside this tender divine love: the two belong together — the loving parent\'s instruction delights the child who recognizes the love behind it.</p>',
    "78": '<p>"May the proud be shamed (<em>yĕḇōšû</em>) — without reason (<em>šeqer</em>) they have twisted things against me; I will reflect on your <em>piqqûdîm</em>" — <em>ʿiwwĕtunî šeqer</em> = "they perverted against me with falsehood" — the false accusation or malicious misrepresentation that harms the psalmist\'s standing. The response is not legal counter-action but meditation on Torah precepts. The honor-shame dynamic: the prayer that the shamer be shamed, and the turning to Torah as the alternative to the social battle.</p>',
    "79": '<p>"Let those who fear you gather around me (<em>yāšûḇû ʾēlay</em>) — those who know your <em>ʿēdôt</em>" — the petition for social solidarity with the Torah-piety community. <em>Yāšûḇ ʾēl</em> = to "turn back to" someone in restored fellowship; the psalmist\'s suffering may have created social isolation, and the petition is for re-gathering of the pious community around the sufferer. The Second Temple <em>ḥăḇûrôt</em> (fellowship groups) would have been the social form of this community.</p>',
    "80": '<p>"May my heart be wholly devoted (<em>yĕhî-libbî tāmîm</em>) to your <em>ḥuqqîm</em>, so I will not be put to shame" — <em>tāmîm</em> = whole, complete, without blemish (the same word applied to the Passover lamb in Exod 12:5 and to the required sacrificial animals — without defect). A "whole heart" in covenant terms is undivided loyalty — the opposite of the double-minded (v. 113: <em>śōʿăpîm</em>). The stanza ends as it began (v. 73): with the prayer for a created being to fully correspond to its creator\'s intention.</p>',
    "81": '<p><strong>Kaph stanza (vv. 81–88)</strong> — כ (Kaph = "palm of hand") opens the darkest stanza of the psalm: near-death experience. "My soul is worn out (<em>kāltâ</em>) waiting for your salvation, but I hope in your word" — <em>kālâ</em> = to be completed, exhausted, spent (used for the fading of a lamp, the ending of breath). The soul has been brought to the point of consumption through waiting for divine rescue. Yet hope in the divine word persists — this is the existential edge of covenant faith.</p>',
    "82": '<p>"My eyes are strained (<em>kālû ʿênay</em>) looking for your word, asking, \'When will you comfort me?\'" — <em>kālâ</em> applies now to the eyes (as in v. 81 to the soul): eyes worn out from strain. The question "when (<em>mātay</em>)?" is the lament genre\'s urgent temporal plea (cf. Ps 13:1-2: "how long, LORD?"). Time itself becomes the enemy when waiting exceeds endurance. The psalmist does not abandon the waiting but intensifies the question.</p>',
    "83": '<p>"I am like a wineskin dried out in the smoke (<em>kĕnōʾd bĕqîṭôr</em>), yet I do not forget your <em>ḥuqqîm</em>" — <em>nōʾd</em> = a skin bottle/wineskin (cf. Josh 9:4, 13); dried and shrunken by smoke, a wineskin became wrinkled, stiff, useless for holding liquid. The smoke-dried wineskin is an image of premature aging and dehydration under hardship. The psalmist compares himself to this — suffering has shrunk and dried him out — yet Torah remains unforgotten. Even useless containers remember what they were made to hold.</p>',
    "84": '<p>"How many days of my life are left (<em>kammâ yĕmê ʿabdeḵā</em>)? When will you bring judgment on those who persecute me?" — the double question about time (how many days remaining? when will judgment come?) intensifies the temporal anguish of v. 82. Ancient people did not have the expectation of long life that modernity assumes; the recognition of limited lifespan combined with unresolved persecution creates eschatological urgency: divine judgment must come before life runs out.</p>',
    "85": '<p>"The proud (<em>zēdîm</em>) have set traps (<em>kārû-lî šîḥôt</em>) for me — people who do not follow your <em>tôrâ</em>" — <em>šîḥâ</em> = pit, trap (cf. Ps 7:15; 57:6 — the wicked digging pits they fall into themselves). The pit-trap is the standard image for mortal threat from enemies. The identification of the trappers as those "who do not follow your Torah" reveals the religious dimension of the persecution: the psalmist is being targeted specifically because of Torah-observance that the opponents reject.</p>',
    "86": '<p>"All your <em>miṣwôt</em> are trustworthy (<em>ʾĕmûnâ</em>); they are hounding me without cause (<em>šeqer</em>) — help me!" — the contrast between the trustworthiness of YHWH\'s commandments and the falsehood (<em>šeqer</em>) of the opponents\' accusations: YHWH\'s word is reliable; the accusation against the psalmist is false. The appeal for help (<em>ʿāzrēnî</em>) is the standard cry of the lament genre — the single imperative that summarizes the entire distress.</p>',
    "87": '<p>"They nearly destroyed me from the earth (<em>kimaʿaṭ killûnî bāʾāreṣ</em>), but I have not abandoned your <em>piqqûdîm</em>" — <em>kimaʿaṭ</em> = "almost" (same word as Ps 119:9 — "nearly a remnant"). The psalmist has been brought to the near-edge of death or social elimination but has not abandoned the precepts. In the context of actual persecution (Maccabean period? Persian period?), this could be literal — Torah-observance as a near-fatal social stance.</p>',
    "88": '<p>"Give me life according to your <em>ḥesed</em>, so that I will obey the decrees that come from your mouth" — the stanza\'s darkest point ends with petition grounded in <em>ḥesed</em>: covenant loyalty as the only basis for renewed life after near-destruction. The link between renewed life and continued Torah-obedience is intrinsic: life is constituted by Torah-keeping, not merely sustained alongside it. The mouth of YHWH — through which Torah comes — is also the source of life-giving breath (Gen 2:7).</p>',
    "89": '<p><strong>Lamed stanza (vv. 89–96)</strong> — ל (Lamed), the first letter of <em>lēḇāḇ</em> (heart), opens the cosmic stability stanza. "Your word, O LORD, stands firm forever (<em>lĕʿôlām niṣṣāḇ bašṣāmayim</em>) — fixed in the heavens" — <em>niṣṣāḇ</em> = stands firm, is stationed (the same word used of the pillar of cloud/fire — Num 14:14). The divine word is not a historical document that ages and decays but a cosmic reality "stationed in the heavens" — as stable as the heavens themselves. This cosmic grounding is the answer to the Kaph stanza\'s near-despair.</p>',
    "90": '<p>"Your faithfulness (<em>ʾĕmûnātĕkā</em>) lasts through every generation — you set the earth in place and it holds firm (<em>wattaʿămod</em>)" — the earth\'s continuing stability is evidence of divine faithfulness: YHWH established the earth (a single act) and it still holds (a continuing state). The cosmological argument for covenantal reliability: if YHWH keeps the earth standing through every generation, he keeps his covenant-word just as reliably. The same God who sustains creation sustains his promises.</p>',
    "91": '<p>"Everything continues to this day according to your <em>mišpāṭîm</em>, for all things serve you (<em>ki ḵol ʿăḇādêkā</em>)" — the entire cosmic order — sun, moon, stars, weather, seasons — operates according to YHWH\'s <em>mišpāṭîm</em> (ordinances). Creation itself is a Torah-keeper; the sun rises on schedule because it obeys. This is the theological background of Jer 31:35-36: "the ordinances of the sun and moon — if these ordinances depart from before me... only then will the offspring of Israel cease to be a nation."</p>',
    "92": '<p>"If your <em>tôrâ</em> had not been my joy (<em>šāʿăšuʿāy</em>), I would have died in my suffering (<em>ʿānyyî</em>)" — the counterfactual is stark: death vs. Torah-joy. Joy in Torah was not a luxury emotion but a survival mechanism — the thing that sustained life under pressure. This is the experiential testimony behind Nehemiah\'s paradox: "the joy of the LORD is your strength (<em>ʿuzzĕkem</em>)" (Neh 8:10) — delivered in the same context of Torah-reading.</p>',
    "93": '<p>"I will never forget your <em>piqqûdîm</em>, for through them you have kept me alive (<em>ḥiyyītanî</em>)" — the experience of the Kaph stanza (vv. 81-88: near-death) is now reflected upon: it was the precepts that kept the psalmist alive through the near-death experience. Memory of this experience grounds the vow of non-forgetting. Gratitude for survival is the motive for perpetual Torah-remembrance.</p>',
    "94": '<p>"I belong to you (<em>lĕkā-ʾănî</em>) — rescue me, for I have devoted myself to your <em>piqqûdîm</em>" — <em>lĕkā-ʾănî</em> (I am yours) is the language of belonging, of ownership that is also devotion. In the ANE, "belonging to" a deity was the normal self-description of worshipers — the name "Isaiah" means "YHWH saves"; "Obadiah" = "servant of YHWH." The psalmist makes this belonging explicit as the ground of the rescue petition.</p>',
    "95": '<p>"The wicked lurk to destroy me, but my attention stays fixed on your <em>ʿēdôt</em>" — the lurking (<em>qiwwû rĕšāʿîm lĕʾabbĕdēnî</em>) is ambush imagery again (cf. v. 85). But the psalmist\'s single-pointed attention (<em>ʾetbônen</em> = I will discern, contemplate) to the testimonies is what enables equanimity under ambush. Contemplation of Torah creates the stable center that cannot be reached by external threat.</p>',
    "96": '<p>"I have seen that every human achievement (<em>lĕḵol tiḵlâ</em>) has its limits, but your <em>miṣwâ</em> has no bounds (<em>rĕḥāḇâ mĕʾōd</em>)" — <em>tiḵlâ</em> (H8503) = completeness, perfection, limit (rare word); even the most complete human accomplishment hits a boundary. <em>Rĕḥāḇâ mĕʾōd</em> = "exceedingly broad/wide" — the commandment is spatially unlimited. The contrast between the bounded character of all human excellences and the unbounded scope of divine instruction is the stanza\'s climax.</p>',
    "97": '<p><strong>Mem stanza (vv. 97–104)</strong> — מ (Mem), the letter of "water" (<em>mayim</em>), opens the love-of-Torah stanza. "How I love (<em>mā-ʾāhaḇtî</em>) your <em>tôrâ</em>! I think about it all day long (<em>kol-hayyôm hî śîḥātî</em>)" — <em>ʾāhēḇ</em> applied to Torah is the love-language of the Shema (Deut 6:5: love YHWH with all your heart); Torah as object of love brings YHWH and Torah into a nearly identical relationship with the lover. All-day meditation (<em>kol-hayyôm</em>) fulfills the Deuteronomic command (Deut 6:7; Josh 1:8).</p>',
    "98": '<p>"Your <em>miṣwôt</em> make me wiser than my enemies (<em>mêʾōyĕḇay tĕḥakkĕmēnî</em>), for they are always with me" — Torah as a wisdom-source superior to enemy intelligence. In the wisdom tradition, wisdom is the supreme practical resource — it enables success in all endeavors. The claim that Torah surpasses the wisdom of enemies was significant in Second Temple contexts where Hellenistic education claimed intellectual superiority over Jewish particularism.</p>',
    "99": '<p>"I understand more than all my teachers (<em>mikkal-mĕlammĕdāy</em>) do, for your <em>ʿēdôt</em> fill my thoughts" — a bold claim of surpassing one\'s teachers. In wisdom tradition, the student who internalizes the teacher\'s instruction eventually exceeds the teacher — not through autonomous brilliance but through the quality of what was taught (Prov 4:1-9). The Torah itself, rather than any human teacher, is the source of the superior understanding.</p>',
    "100": '<p>"I discern more than those who are older (<em>mizzĕqēnîm</em>), because I observe your <em>piqqûdîm</em>" — to claim superiority over elders (who held authority by virtue of age and experience in the ANE) was socially provocative. The basis of the claim is not youthful arrogance but Torah-observance. This echoes the wisdom tradition where the young Elihu claims understanding beyond Job\'s older friends because of the spirit\'s instruction (Job 32:6-10).</p>',
    "101": '<p>"I have kept my feet from every wrong path (<em>darreḵ rāʿ</em>) so that I could obey your word" — the "wrong path" (<em>dereḵ rāʿ</em>) is the Wisdom tradition\'s standard for the path of moral failure (Prov 1:15-16; 2:12-14; 4:14-15). Keeping the feet from it requires constant, proactive avoidance — not passive non-engagement but active turning away. The image is of a traveler who constantly monitors his route against the standard of the divine word.</p>',
    "102": '<p>"I have not turned away from your <em>mišpāṭîm</em>, for you yourself have been my teacher (<em>hôrētanî</em>)" — the key claim: YHWH is the direct teacher, not a human intermediary. <em>Yārāh</em> (hiphil: to shoot, point, teach) is the verb from which <em>tôrâ</em> (teaching) derives. When YHWH himself is the teacher, the psalmist\'s non-turning is grounded in the quality of the instruction — one does not turn from the teaching of the supreme teacher.</p>',
    "103": '<p>"How sweet (<em>mah-nimlĕṣû</em>) your words are to me — sweeter than honey in my mouth!" — <em>mālaṣ</em> (H4452) = to be pleasant, sweet. The honey-metaphor for Torah appears also in Ps 19:10 ("sweeter also than honey and drippings from the honeycomb") and Ezek 3:3 (Ezekiel\'s scroll tasting sweet as honey). In the ancient world, honey was the sweetest known substance; applying its standard to divine words is the ultimate taste-metaphor for desirability. The mouth/taste imagery emphasizes experiential knowledge of Torah, not merely cognitive.</p>',
    "104": '<p>"Your <em>piqqûdîm</em> give me discernment (<em>mippiqqûdêkā ʾetbônān</em>); that is why I hate (<em>śānēʾtî</em>) every path of falsehood (<em>dereḵ šeqer</em>)" — Torah-given discernment produces the capacity to hate falsehood — not mere avoidance but active rejection. In the Wisdom tradition, the love of wisdom and the hatred of folly are two sides of the same moral coin (Prov 8:13: "the fear of the LORD is to hate evil"). The psalmist\'s hatred of falsehood is the negative expression of the love of Torah.</p>',
    "105": '<p><strong>Nun stanza (vv. 105–112)</strong> — נ (Nun) opens the "lamp and light" stanza, perhaps the most quoted verse in Ps 119. "Your word is a lamp (<em>nēr</em>) that lights my feet and a light (<em>ʾôr</em>) for my path" — <em>nēr</em> = lamp (small, hand-carried oil lamp for immediate vicinity); <em>ʾôr</em> = light (broader illumination). The lamp-for-feet provides the next step; the light-for-path provides orientation over distance. Torah as both immediate guidance and long-range direction. In the darkness of an ancient world without street lighting, a lamp was the difference between safe travel and stumbling into pits.</p>',
    "106": '<p>"I have taken an oath (<em>nišbaʿtî</em>) and will hold to it: I will follow your righteous <em>mišpāṭîm</em>" — oath-taking was the most solemn form of commitment in the ancient world: to break an oath was to invoke divine curse on oneself (cf. the covenant-oath formulas in Deut 27-28). The psalmist binds himself by oath to Torah-keeping — treating covenant relationship not as a preference but as a sworn obligation. This is the deliberate appropriation of the Sinai covenant oath.</p>',
    "107": '<p>"I am deeply afflicted (<em>nĕʿĕnêtî ʿad-mĕʾōd</em>) — give me life again, LORD, as you have promised!" — the affliction formula returns (cf. vv. 25, 28, 50, 67, 71, 75); the psalm is embedded in real suffering, not hypothetical devotion. The life-restoring word (<em>kibdĕḇārêkā</em> = "as your word/promise") — the appeal is to a prior divine promise whose fulfillment is now being sought. Ancient Near Eastern prayer regularly appealed to specific divine promises as the basis for petition.</p>',
    "108": '<p>"O LORD, please accept (<em>rĕṣēh-nāʾ</em>) the willing praise of my lips and teach me your <em>mišpāṭîm</em>" — <em>nidḇôt pî</em> = "freewill/voluntary offerings of my mouth" — the term <em>nĕdāḇâ</em> (freewill offering) is the technical term for a sacrificial offering given beyond what was legally required (Lev 22:18; Deut 12:6). The psalmist brings a verbal freewill offering — praise that goes beyond the required minimum. The language applies sacrificial vocabulary to speech, a spiritualization of cult.</p>',
    "109": '<p>"I hold my life in my hands at every moment (<em>napšî ḇĕkappî tāmîd</em>), yet I do not forget your <em>tôrâ</em>" — <em>napšî ḇĕkappî</em> = "my life in my palm" — the idiom for living in constant danger (also Judg 12:3; 1 Sam 19:5; Job 13:14). The palm of the hand is both fragile and open — the life held there is constantly at risk of slipping out. In the face of constant mortal danger, Torah-remembrance is the psalmist\'s centering act.</p>',
    "110": '<p>"The wicked laid a trap (<em>pāḥ</em>) for me, but I have not wandered from your <em>piqqûdîm</em>" — <em>pāḥ</em> (H6341) = a spring-trap (for birds — cf. Ps 91:3; 124:7; Prov 7:23). The trap-imagery for mortal danger from enemies (cf. vv. 85, 87) again; the test of Torah-faithfulness is precisely whether the threat of the trap changes the psalmist\'s conduct. It does not — the precepts remain the guiding orientation despite the trap.</p>',
    "111": '<p>"Your <em>ʿēdôt</em> are mine as an inheritance (<em>naḥălâ</em>) forever — they are the joy of my heart" — <em>naḥălâ</em> (inheritance) is the covenantal word for Israel\'s land and for each tribe\'s portion. By describing the testimonies as his inheritance, the psalmist completes the Levitical theology of v. 57 (YHWH as portion): Torah is the Levitical inheritance — not land but instruction. This inheritance is "forever" (unlike land which can be lost to conquest).</p>',
    "112": '<p>"I have set my heart (<em>nāṭîtî libbî</em>) on keeping your <em>ḥuqqîm</em> always — right to the end (<em>ʿēqeḇ</em>)" — <em>nāṭâ lēḇ</em> = "to incline/set the heart toward" — a deliberate act of internal orientation, not passive drift. <em>ʿĒqeḇ</em> (H6118) = end, heel, consequence; the "end" here is both "forever" and "to the last consequences." The stanza closes with the psalmist\'s full volitional commitment: the heart set, the end in view, the <em>ḥuqqîm</em> held forever.</p>',
    "113": '<p><strong>Samek stanza (vv. 113–120)</strong> — ס (Samek) is the stanza of single-mindedness. "I hate (<em>śānēʾtî</em>) those who are half-hearted (<em>śōʿăpîm</em>), but your <em>tôrâ</em> I love" — <em>śōʿēp̄</em> (H5588) is disputed but likely means "double-minded" or "those who limp on two opinions" (cf. 1 Kgs 18:21 — "how long will you waver between two opinions?"). The psalmist\'s single-minded Torah-love is defined against double-mindedness. This verse stands behind James 1:8 ("a double-minded person is unstable in all their ways").</p>',
    "114": '<p>"You are my shelter (<em>mastər</em>) and my shield (<em>māgēn</em>) — I hope in your word" — <em>mister</em> = hiding place, concealment (cf. Ps 32:7: "you are my hiding place"); <em>māgēn</em> = shield (the warrior\'s defensive weapon). The pair covers defensive concealment and active protection. YHWH as both the hiding place (passive safety) and the shield (active protection) provides comprehensive security — the basis for the hope in the divine word.</p>',
    "115": '<p>"Get away from me (<em>sûrû-mimmennî</em>), you who do evil — I intend to keep (<em>wĕʾeṣṣĕrâ</em>) the commands of my God" — the dismissal of evildoers is a social act as well as a moral one: the psalmist explicitly chooses separation from their company. In Second Temple Judaism, the purity-separation from the impure and the wicked was a significant social practice (the <em>ḥăḇûrôt</em> maintained purity boundaries against ordinary Israelites; the Qumran community took this to its extreme). The psalmist\'s "get away" echoes this separatist piety.</p>',
    "116": '<p>"Sustain me as you have promised (<em>kĕʾimrātĕkā</em>) so I may live — do not let my hope put me to shame (<em>wĕʾal-tĕḇîšēnî</em>)" — the shame-petition in the context of hope: if YHWH does not fulfill his promise, the psalmist\'s publicly stated hope is exposed as vain. To be shamed in one\'s hope is to have the patron refuse the petition, thereby publicly humiliating the supplicant. The petition protects both the psalmist\'s honor and YHWH\'s reputation as a promise-keeper.</p>',
    "117": '<p>"Support me (<em>sĕʾādēnî</em>) and I will be safe (<em>wĕʾiwwāšēʿâ</em>), and I will keep my gaze fixed on your <em>ḥuqqîm</em> always" — <em>sāʿad</em> = to support, to uphold (used of providing food — "to sustain the heart" — Gen 18:5; Ps 104:15); the metaphor of divine support as the physical provision that enables continued movement. Safety (<em>yāšaʿ</em>) as the fruit of divine support — the salvation-vocabulary grounded in the support metaphor.</p>',
    "118": '<p>"You reject (<em>sālîtā</em>) all who drift away (<em>šāgû</em>) from your <em>ḥuqqîm</em> — their deceptions are empty lies (<em>šeqer</em>)" — <em>sālal</em> (H5541) = to reject, make light of, despite; the divine rejection of those who drift from the statutes is categorical. <em>Šāgû</em> = to wander, err (not necessarily deliberate — the word can describe innocent mistakes, Lev 4:13; but also culpable spiritual wandering). The "deceptions" (<em>tarmît</em>) of those who drift are exposed as <em>šeqer</em> — the path of deception leads nowhere.</p>',
    "119": '<p>"You sweep away all the wicked of the earth like impure dross (<em>kisgîm</em>) — therefore I love your <em>ʿēdôt</em>" — <em>sîgîm</em> = slag, dross (the waste from metal smelting — cf. Isa 1:22, 25; Prov 25:4; 26:23). The metaphor of divine judgment as metallurgical refining: YHWH as the refiner removes the dross (the wicked) from the earth. The psalmist\'s love for the testimonies is grounded in this refining action — YHWH\'s active purification of the earth confirms the worth of what he requires.</p>',
    "120": '<p>"I tremble in awe of you (<em>sāmar mippāḥdĕkā bĕśārî</em>) — your judgments fill me with holy dread (<em>yārēʾtî</em>)" — <em>sāmar</em> = to bristle, stand on end (of hair or skin), tremble; the physical gooseflesh response to overwhelming divine presence or power. This is the <em>numinous</em> experience described by Rudolf Otto as the <em>mysterium tremendum</em>: the overwhelming, terrifying holiness of the divine that both attracts and repels. The psalmist is not afraid of YHWH\'s <em>mišpāṭîm</em> punishing him; he stands in awe of the sheer weight of divine authority.</p>',
    "121": '<p><strong>Ayin stanza (vv. 121–128)</strong> — ע (Ayin = "eye"), the stanza of justice and appeal. "I have acted with justice and integrity (<em>ʿāśîtî mišpāṭ wāṣedeq</em>) — do not hand me over to those who oppress me" — the appeal to personal righteousness as grounds for divine protection. The pairing <em>mišpāṭ</em> + <em>ṣedeq</em> (justice + righteousness) is the canonical formulation of covenant justice (Amos 5:24; Isa 1:21; Ps 89:14). The psalmist\'s appeal is not boastfulness but a covenant argument: those who practice covenant justice deserve covenant protection.</p>',
    "122": '<p>"Guarantee good things (<em>ʿărōb ʿabdĕkā lĕṭôḇ</em>) for your servant — do not let the proud trample me" — <em>ʿārab</em> (H6148) = to serve as surety, to pledge oneself as guarantor (the financial term for a person who pledges themselves as security for another\'s debt — Gen 43:9; 44:32; Prov 11:15; 22:26). The petition is for YHWH to be the psalmist\'s guarantor — to stand surety for the psalmist against the threatening claims of the proud. The financial metaphor applied to divine protection is vivid.</p>',
    "123": '<p>"My eyes are worn out (<em>ʿênay kālû</em>) watching for your salvation and for the fulfillment of your righteous promise (<em>lĕʾimrat ṣidqêkā</em>)" — <em>kālâ</em> (spent/exhausted) applies now to the eyes (cf. v. 82). Watching for salvation implies a specific rescue that has been promised but not yet fulfilled — the experience of delayed fulfillment that tests faith. The "righteous promise (<em>ʾimrat ṣidqêkā</em>)" is the divine word that will prove its righteousness when it is fulfilled.</p>',
    "124": '<p>"Treat your servant according to your <em>ḥesed</em> and teach me your <em>ḥuqqîm</em>" — the petition for treatment "according to <em>ḥesed</em>" rather than according to strict merit is the standard OT lament-petition (cf. Ps 51:1 — "according to your great mercy"). <em>Hesed</em> exceeds what is strictly owed; it is the overflow of covenant loyalty beyond legal requirement. Teaching the statutes is requested as an act of <em>ḥesed</em> — generous instruction given to one who does not deserve it by merit alone.</p>',
    "125": '<p>"I am your servant (<em>ʿaḇdĕkā ʾānî</em>) — give me discernment (<em>hăḇînēnî</em>) to understand your <em>ʿēdôt</em>" — the servant-identity (<em>ʿeḇed</em>) is both the humblest and the most honored address in biblical covenant language. Great figures are called "servant of YHWH": Moses (Deut 34:5), Joshua (Josh 24:29), David (Ps 89:3), Isaiah\'s Servant (Isa 42:1). To be YHWH\'s servant is not degradation but the highest possible station — and it grounds the request for instruction: servants must understand their master\'s orders.</p>',
    "126": '<p>"It is time for you to act (<em>ʿēt laʿăśôt laYHWH</em>), LORD — they have rendered your <em>tôrâ</em> void (<em>hēpērû</em>)" — the most urgent petition in the psalm; possibly the most theologically bold. <em>Hēpērû tôrātêkā</em> = "they have broken/annulled your Torah." When Torah is publicly nullified — by hostile rulers, by social power — the psalmist calls on YHWH to act on behalf of his own reputation (cf. Ezek 20:9, 14, 22 — YHWH acts for the sake of his name). The urgency of YHWH\'s honor as the grounds for intervention.</p>',
    "127": '<p>"Therefore I love your <em>miṣwôt</em> more than gold — more than the finest gold (<em>mizzāhāḇ ûmippāz</em>)" — <em>pāz</em> (H6337) = pure gold (the finest quality, also in Ps 21:3; Song 5:11; Prov 8:19). The Torah-surpasses-gold comparison reaches its most intense form here, after the crisis of v. 126: precisely when Torah is being violated by others, the psalmist\'s personal valuation of Torah intensifies. Persecution of Torah produces intensified Torah-love.</p>',
    "128": '<p>"For that reason I consider all your <em>piqqûdîm</em> to be right in every area, and I hate every path of falsehood" — the comprehensive rightness of the precepts and the comprehensive hatred of falsehood mirror each other: totality of affirmation matches totality of rejection. "Every path of falsehood" recalls v. 29 and v. 104; the triple occurrence in the psalm makes it the defining opposite of Torah. What Torah is true, falsehood is false — completely, without remainder.</p>',
    "129": '<p><strong>Pe stanza (vv. 129–136)</strong> — פ (Pe = "mouth"), appropriately the stanza of words and their effect. "Your <em>ʿēdôt</em> are wonderful (<em>pĕlāʾôt</em>) — that is why I treasure them" — <em>peleʾ</em> (H6382) = wonder, extraordinary act (from the same root as the plagues of Egypt, the Exodus miracles). The testimonies are not merely instructive but wonderful in the way divine acts are wonderful — they exceed human expectation and reveal divine character. Treasuring what is wonderful (<em>nāṣar</em> = to guard, keep carefully) is the natural response.</p>',
    "130": '<p>"When your words are opened up (<em>pēteaḥ dĕḇārêkā</em>) they shed light (<em>yāʾîr</em>); they give understanding (<em>mēḇîn</em>) to the untrained mind (<em>pĕtāyim</em>)" — <em>pōtēaḥ</em> (opening) applied to the words: as a door opens to admit light, so Torah-words open to illuminate. <em>Pĕtāyim</em> = simple/naive (Prov 1:4; 8:5 — those who lack experience); the Torah that gives wisdom to the wise also illuminates those who lack education. This democratizing of wisdom through Torah is a distinctive Israelite contribution to ancient thought.</p>',
    "131": '<p>"I opened my mouth and panted in longing (<em>pĕʿartî pî wāʾešʾāpâ</em>) — I craved your <em>miṣwôt</em>" — two physical images: opening the mouth wide (like a hungry animal) and panting (the breath of desire or exertion). The appetite-metaphor for Torah-longing is intentionally physical: the desire for Torah instruction is as visceral and involuntary as hunger and thirst. This verse connects to Ps 42:1 ("as the deer pants for streams of water, so my soul pants for you") and John 7:37 ("if anyone is thirsty, let him come to me").</p>',
    "132": '<p>"Look on me and be merciful, as is your custom (<em>kĕmišpāṭ</em>) toward those who love your name" — <em>kĕmišpāṭ</em> = "according to your right practice/custom" — an appeal to YHWH\'s established pattern of behavior. YHWH\'s mercy to those who love his name is not an exceptional request but a consistent covenant pattern; the psalmist appeals to YHWH\'s track record. "Loving the name" = the complete loyalty to YHWH expressed through Torah-keeping.</p>',
    "133": '<p>"Keep my steps firm (<em>hākēn pĕʿāmay bĕʾimrātêkā</em>) in your word and do not let any sin take control (<em>yišlāṭ-bî kol-ʾāwen</em>) of me" — <em>hēkîn</em> = to prepare, establish, make firm (the creation-word of v. 90); the petition is for the same cosmic stability that YHWH gave the earth to be given to the psalmist\'s steps. <em>Yišlāṭ</em> = to exercise dominion over (cf. Gen 1:28 — the word for human dominion over creation). The petition: do not let sin exercise the dominion that belongs only to YHWH.</p>',
    "134": '<p>"Set me free (<em>pĕdēnî</em>) from human cruelty (<em>mēʿōšeq ʾāḏām</em>), and I will keep your <em>piqqûdîm</em>" — <em>pādâ</em> (H6299) = to redeem, ransom (the technical word for the payment that frees a slave, redeems a firstborn, or ransoms a prisoner). The psalmist asks to be "ransomed" from human oppression as a precondition for full Torah-keeping. The implication: oppression impedes Torah-observance, not merely morally but practically. Freedom from oppression is a precondition for covenant life.</p>',
    "135": '<p>"Let your face shine (<em>hāʾēr pānêkā</em>) on your servant and teach me your <em>ḥuqqîm</em>" — the shining face (<em>pānîm</em>) is the priestly blessing formula (Num 6:25: "the LORD make his face shine upon you"). The high-priestly blessing invoked over Israel becomes a personal petition. The "shining face" of God is his favor turned toward the petitioner — the opposite of the hidden face of vv. 19, 132. To be under the divine face-shine is to be in the most favorable covenant position.</p>',
    "136": '<p>"My eyes pour down rivers of tears (<em>palgê-mayim yārĕdû ʿênāy</em>) because people do not keep your <em>tôrâ</em>" — the weeping is for the violation of Torah by others, not merely for personal suffering. This is the prophetic sorrow for communal sin: Jeremiah weeping over Jerusalem (Jer 9:1; 14:17; Lam 1:16), Ezra tearing his garments (Ezra 9:3-5), Nehemiah weeping over Jerusalem\'s walls (Neh 1:4). The psalmist participates in the prophetic tradition of vicarious grief for Israel\'s covenant failure.</p>',
    "137": '<p><strong>Tsade stanza (vv. 137–144)</strong> — צ (Tsade), the letter of <em>ṣaddîq</em> (righteous), opens the righteousness stanza. "You are righteous (<em>ṣaddîq ʾattâ YHWH</em>), O LORD, and your <em>mišpāṭîm</em> are just (<em>yāšār</em>)" — the declaration of divine righteousness grounds the stanza. YHWH\'s <em>ṣedeq</em> is his covenant faithfulness expressed in right action; it is both character and conduct. The affirmation is not merely theological but contextual — made in the midst of the suffering described throughout the psalm.</p>',
    "138": '<p>"The <em>ʿēdôt</em> you have commanded are righteous (<em>ṣedeq</em>) and completely trustworthy (<em>ʾĕmûnâ mĕʾōd</em>)" — the testimonies inherit the character of the one who issues them: YHWH is righteous, therefore his testimonies are righteous; YHWH is faithful, therefore his testimonies are completely trustworthy. The reliability of Torah is derivative from the character of YHWH — not an independent property of the text but a property conferred by the author.</p>',
    "139": '<p>"A burning zeal (<em>qinʾātî</em>) has consumed me, because my enemies disregard your words (<em>šāḵĕḥû dĕḇārêkā</em>)" — <em>qinʾâ</em> (H7068) = zeal, jealousy; the passion of exclusive loyalty to YHWH that cannot tolerate a rival (Exod 20:5 — "I, the LORD your God, am a jealous God"). The psalmist\'s zeal mirrors YHWH\'s own jealousy for his name. The connection to Ps 69:9 ("zeal for your house has consumed me") is explicit; the NT applies that verse to Jesus (John 2:17).</p>',
    "140": '<p>"Your word (<em>ʾimrātĕkā</em>) is completely pure (<em>ṣĕrûpâ mĕʾōd</em>) — that is why your servant loves it" — <em>ṣārap̄</em> = to refine, smelt (metals); <em>ṣĕrûpâ</em> = refined/proven/pure. The divine word compared to refined metal appears also in Ps 12:6 ("the words of the LORD are flawless, like silver purified in a crucible"). Unlike the dross-laden speech of human beings (Ps 12:2-4), YHWH\'s word is pure because it has been through the refiner\'s fire — or rather, it is the standard by which the fire refines everything else.</p>',
    "141": '<p>"I am lowly and scorned (<em>ṣāʿîr wĕniḇzeh</em>), but I have not forgotten your <em>piqqûdîm</em>" — <em>ṣāʿîr</em> = small, young, insignificant; <em>niḇzeh</em> = despised (the Servant is <em>niḇzeh</em> in Isa 53:3). The social invisibility of the psalmist ("lowly and scorned") combines with the persistence of Torah-memory. The small and despised person who retains Torah is the social inversion that the psalm consistently celebrates — the humble Torah-keeper against the proud Torah-violators.</p>',
    "142": '<p>"Your righteousness (<em>ṣidqātĕkā</em>) stands forever (<em>lĕʿôlām</em>), and your <em>tôrâ</em> is truth (<em>ʾĕmet</em>)" — the pair <em>ṣĕdāqâ</em> (righteousness) and <em>ʾĕmet</em> (truth) are the two core attributes of the divine character that Torah expresses. <em>Ṣĕdāqâ</em> is the relational faithfulness-in-action; <em>ʾĕmet</em> is the reliability that makes YHWH trustworthy. Both are "forever (<em>lĕʿôlām</em>)" — they do not shift with cultural or political change.</p>',
    "143": '<p>"Distress and trouble (<em>ṣar-ûmāṣôq</em>) have overtaken me, yet your <em>miṣwôt</em> are my delight" — <em>ṣar</em> + <em>māṣôq</em> = two words for pressing distress (cf. Deut 28:53, 55, 57 — the covenant-curse words for siege-distress). The overlap between these words and the covenant-curse vocabulary of Deuteronomy 28 is not coincidental; the psalmist may be describing the experience of living under the covenant curses. Yet delight in Torah persists — the experience that deepens Torah-love rather than destroying it.</p>',
    "144": '<p>"Your <em>ʿēdôt</em> are right for all time (<em>ṣedeq lĕʿôlām</em>) — give me understanding so I may live (<em>hăḇînēnî wĕʾeḥyeh</em>)" — the stanza closes with the conjunction of eternal Torah and contingent life: the testimonies are forever righteous, but the psalmist\'s life is contingent on divine gift. Understanding (<em>bînâ</em>) is the key: comprehension of eternal righteousness is what sustains temporal life. The pairing reappears in v. 169 (the Taw stanza\'s opening).</p>',
    "145": '<p><strong>Qoph stanza (vv. 145–152)</strong> — ק (Qoph = "back of head/eye of needle") opens the urgent-prayer stanza. "I called out (<em>qārāʾtî</em>) with all my heart — answer me, LORD! I will keep your <em>ḥuqqîm</em>" — the qol-level of prayer escalates here: "with all my heart" (<em>bĕḵol-lēḇ</em>) is the Shema-level intensity. The condition attached to the petition ("I will keep your <em>ḥuqqîm</em>") is a vow: if YHWH answers, the psalmist commits to Torah-keeping. This is the vow-petition form of lament psalms.</p>',
    "146": '<p>"I called out to you — save me (<em>hôšîʿēnî</em>), so I can keep your <em>ʿēdôt</em>" — the salvation petition connects the act of rescue to its purpose: saving the psalmist enables continued Torah-keeping. The psalmist\'s life is instrumentalized for Torah: rescue is not desired for itself but as the means of covenant faithfulness. This reversal of normal self-interest (seeking rescue primarily to benefit oneself) is the psalm\'s distinctive theological claim.</p>',
    "147": '<p>"I am awake before daybreak (<em>qiḏḏamtî ḇanneśep̄</em>) to cry out — I put my hope in your word" — <em>neśep̄</em> = the last watch of the night, just before dawn (one of three OT night watches — Exod 14:24; 1 Sam 11:11). The pre-dawn prayer was the most extreme form of night prayer — cutting short sleep to begin before daylight. This practice appears in the prophets (Isa 26:9: "my soul yearns for you in the night; in the morning my spirit longs for you"), in the psalms (Ps 57:8; 63:1), and in Jesus\'s early-morning prayer (Mark 1:35).</p>',
    "148": '<p>"I am awake through the night watches (<em>qiḏḏamû ʿênay ʾašmurôt</em>) to reflect on your word" — <em>ʾašmurôt</em> = night watches (three periods: sunset to midnight, midnight to pre-dawn, pre-dawn to sunrise). The psalmist is awake through the watches — the entire night given to Torah-meditation. This verse, with v. 147, creates a night-to-dawn prayer bracket: praying in the deep of night and continuing through every watch until dawn. The Second Temple and early Christian all-night prayer vigil finds its scriptural foundation here.</p>',
    "149": '<p>"Listen to me, LORD, in your <em>ḥesed</em> — give me life according to your justice (<em>kĕmišpāṭêkā</em>)" — a double appeal: to <em>ḥesed</em> (covenant loyalty that exceeds strict obligation) and to <em>mišpāṭ</em> (judicial right). Both are invoked simultaneously — not as contradictory principles but as two aspects of the same divine character. The justice of YHWH as life-giving rather than merely punitive is the psalm\'s consistent claim.</p>',
    "150": '<p>"Those who chase after wickedness (<em>rōdĕpê zimmâ</em>) are closing in — they are far from your <em>tôrâ</em>" — <em>zimmâ</em> (H2154) = wickedness, evil plan/scheme, lewdness (a strong word also used for sexual immorality, Lev 18:17; 19:29; 20:14). The closing-in imagery: the distance of the wicked from Torah is in inverse proportion to their proximity to the psalmist. Those farthest from Torah are nearest to the Torah-keeper as a target.</p>',
    "151": '<p>"But you are near (<em>qārôḇ ʾattâ YHWH</em>), O LORD — all your <em>miṣwôt</em> are truth" — the nearness of YHWH answers the nearness of the wicked persecutors (v. 150). Two proximities: the wicked close in from outside; YHWH is near from within. The divine nearness — guaranteed by the truthfulness of the commandments — is the psalm\'s answer to every threat. This verse stands behind Deut 4:7 ("what great nation has a god so near to them as the LORD our God is to us").</p>',
    "152": '<p>"I have known from ancient times (<em>miqqedem yāḏaʿtî</em>) about your <em>ʿēdôt</em> — you established them to last forever" — "ancient times" here is the psalmist\'s own prior knowledge: the testimonies are old, well-established, unchanging. The permanence of YHWH\'s testimonies is the final answer to every circumstantial pressure: no crisis can make them expire. They were established <em>lĕʿôlām</em> (forever) and remain so — the rock of cosmic stability from the Lamed stanza (vv. 89-91) reappears.</p>',
    "153": '<p><strong>Resh stanza (vv. 153–160)</strong> — ר (Resh), the stanza of seeing and rescue. "Look at (<em>rĕʾē</em>) my suffering and rescue me, for I have not forgotten your <em>tôrâ</em>" — the petition for YHWH to "look" (<em>rāʾâ</em>) echoes Exod 3:7 ("I have indeed seen the misery of my people"). The divine seeing that initiates rescue: when YHWH looks at suffering, he acts. The psalmist\'s not-forgetting of Torah is the moral basis for the appeal: the covenant-faithful deserve covenant rescue.</p>',
    "154": '<p>"Take up my case (<em>rîḇâ rîḇî</em>) and rescue me — give me life as you have promised" — <em>rîḇ</em> = lawsuit, legal case, dispute (cf. Ps 119:153; Lam 3:58-59). The petition for YHWH to act as the psalmist\'s legal advocate — to take up the case and argue it before the court of justice. YHWH as divine attorney/advocate is a Psalms motif (Ps 35:1; 43:1; Prov 22:23; 23:11). The legal frame: life is owed to the psalmist because YHWH has committed to the case.</p>',
    "155": '<p>"Rescue (<em>yĕšûʿâ</em>) is far from the wicked — they have no interest (<em>lōʾ dāršû</em>) in your <em>ḥuqqîm</em>" — the absence of Torah-seeking is the cause of the absence of salvation. The causality is theological: those who do not seek (<em>dāraš</em>) the statutes have placed themselves outside the covenant that brings rescue. Seeking Torah and seeking YHWH are functionally identical (cf. Amos 5:4-6: "seek me and live... seek good and not evil, that you may live").</p>',
    "156": '<p>"Your compassion (<em>raḥămêkā</em>) is vast (<em>rabbîm</em>), O LORD — give me life according to your <em>mišpāṭîm</em>" — <em>rabbîm</em> (many/great/vast) applied to divine compassion: the vast quantity of YHWH\'s womb-love exceeds the demand being made on it. The appeal to the vastness of divine compassion as sufficient for the need is standard lament-theology (Ps 51:1 — "according to your great mercy"; Ps 86:5 — "abounding in love to all who call to you").</p>',
    "157": '<p>"I have many persecutors and enemies (<em>rabbîm rōdĕpay wĕṣāray</em>), yet I have not turned from your <em>ʿēdôt</em>" — the correlation: <em>rabbîm</em> (many) persecutors countered by non-turning from the testimonies. The many against the one; the numerical imbalance does not produce apostasy. This is the Second Temple martyr-ideal: the community under persecution that holds to Torah despite overwhelming opposition.</p>',
    "158": '<p>"I saw (<em>rāʾîtî</em>) those who were disloyal (<em>bōgdîm</em>) and it grieved me (<em>wāʾetqôṭṭāh</em>), because they do not keep your word (<em>ʾimrātêkā</em>)" — <em>bāgad</em> = to be faithless, treacherous, to act as a traitor (the word used for marital unfaithfulness in Jer 3:20; Mal 2:14-16). The psalmist\'s grief is not at personal suffering caused by the disloyal but at their disloyalty itself — the covenantal grief of the person who loves what they are violating.</p>',
    "159": '<p>"See how much I love (<em>rĕʾē kî-piqqûdêkā ʾāhāḇtî</em>) your <em>piqqûdîm</em>! Give me life, LORD, in your <em>ḥesed</em>" — the appeal "see" echoes v. 153\'s "look at my suffering." Now the content of the divine seeing is different: not the suffering but the love. The love of the precepts is offered as the evidence of covenant loyalty that grounds the petition for life. YHWH is invited to observe the evidence.</p>',
    "160": '<p>"The whole of your word (<em>rōʾš dĕḇārĕkā ʾĕmet</em>) is truth, and every one of your righteous <em>mišpāṭîm</em> stands forever" — <em>rōʾš</em> = head, sum, beginning: "the sum/entirety of your word is truth." Not parts of it, not the best parts — the whole. This comprehensive truthfulness is the stanza\'s conclusion: every part and all of it together is trustworthy. The combination of "entirety" (<em>rōʾš</em>) and "every one (<em>kol</em>)" makes the claim absolute.</p>',
    "161": '<p><strong>Shin stanza (vv. 161–168)</strong> — ש (Shin), the letter of both <em>šālôm</em> (peace) and <em>šeqer</em> (falsehood) — the stanza holds both. "Rulers (<em>śārîm</em>) have hounded (<em>rĕdāpûnî</em>) me without any reason (<em>ḥinnām</em>), but my heart trembles in reverence (<em>pāḥad</em>) before your word" — <em>ḥinnām</em> = "without cause/for nothing" (the word in Job 1:9 for Job\'s undeserved suffering; in Ps 35:19 for enemies who hate without cause; in John 15:25 applied to hatred of Jesus). Persecution without cause is the purest form of unjust suffering.</p>',
    "162": '<p>"I rejoice (<em>śāś</em>) over your word like someone finding a great treasure (<em>šālāl rāb</em>)" — <em>śālāl</em> = booty, plunder (what a victorious army takes). The simile of Torah-joy as battle-prize plunder is unexpected: the psalmist\'s interior joy at the divine word is as intense as a warrior\'s exhilaration at winning great spoil. The joy is disproportionate to the circumstances of persecution (v. 161) — Torah-joy exists independently of social circumstances.</p>',
    "163": '<p>"I deeply hate falsehood and deception (<em>šeqer śānēʾtî wāʾăṯaʿēḇâ</em>), but I love your <em>tôrâ</em>" — <em>šeqer</em> + <em>tĕʿēḇâ</em>: two levels of rejection — hate plus calling abominable (<em>tôʿēḇâ</em> = the strongest disgust-word). The love-hate contrast is absolute: maximum love for Torah, maximum hatred for its opposite. The intensity of the antithesis reflects the complete incompatibility of Torah and falsehood — they are not on a spectrum but are mutually exclusive orientations.</p>',
    "164": '<p>"Seven times each day I praise you (<em>šeḇaʿ bayyôm hillaltîkā</em>) because your <em>mišpāṭîm</em> are just" — "seven times a day" is a comprehensiveness formula (seven = totality in Hebrew numerology), not literally seven discrete prayer sessions (though cf. Ps 55:17 — three times; Dan 6:10 — three times a day). Prayer pervades the entire day. This verse became one of the foundations for the canonical prayer hours in Jewish (Shacharit, Mincha, Maariv and additional services) and Christian (Divine Office, Breviary) tradition.</p>',
    "165": '<p>"Those who love your <em>tôrâ</em> enjoy great peace (<em>šālôm rāb</em>) — nothing will trip them up (<em>ʾên-lāmo mikšôl</em>)" — <em>šālôm rāb</em> = abundant/great peace — the wholeness and completeness of the covenant blessing (cf. Num 6:26; Isa 54:13). <em>Mikšôl</em> = stumbling block, occasion of falling (cf. Isa 57:14 — "remove every obstacle from my people\'s path"). The peace of Torah-lovers is not merely emotional but ontological — they are not tripped up because they are oriented rightly toward reality.</p>',
    "166": '<p>"I put my hope in your salvation, O LORD, and I have carried out (<em>ʿāśîtî</em>) your <em>miṣwôt</em>" — the hope-obedience pairing: hope for future salvation and present obedience are not alternatives but complements. The person who genuinely hopes for YHWH\'s salvation keeps his commandments as the expression of that hope — not as a way of earning the salvation but as evidence of the relationship in which it is sought.</p>',
    "167": '<p>"I have kept (<em>šāmartî</em>) your <em>ʿēdôt</em> with my whole being (<em>bĕnapšî</em>) and I love them deeply (<em>wāʾōhăḇēm mĕʾōd</em>)" — <em>napšî</em> = my whole being/life-self (not merely my inner thoughts but the entirety of the person). The testimony that the keeping of the testimonies is a whole-being act — not compartmentalized religious observance but total personal engagement. <em>Mĕʾōd</em> (exceedingly/greatly) intensifies the love: not moderate affection but deep passion.</p>',
    "168": '<p>"I have obeyed your <em>piqqûdîm</em> and your <em>ʿēdôt</em> — all my ways (<em>kol-dĕrāḵāy</em>) are open before you (<em>nĕḡdêkā</em>)" — the stanza closes with total transparency: the psalmist\'s obedience of precepts and testimonies is offered with the acknowledgment that all his ways are visible to YHWH. <em>Nĕgd</em> = before, in front of, in the direct sight of. The final word of the Shin stanza: the psalmist lives coram Deo ("before the face of God"), and this transparency is not terrifying but confirming — the obedience claimed is genuinely open to divine scrutiny.</p>',
    "169": '<p><strong>Taw stanza (vv. 169–176)</strong> — ת (Taw), the final letter of the alphabet, completes the acrostic. "Let my cry (<em>rinnātî</em>) reach you (<em>tiqqarab lĕpānêkā</em>), O LORD — grant me understanding as you have promised (<em>kibdĕḇārêkā</em>)" — <em>rinnâ</em> = a ringing cry, a shout of joy or distress (cf. Ps 17:1; 61:1; 88:2). The final stanza opens with the most urgent petition of the psalm: the cry reaching the divine face. <em>Kibdĕḇārêkā</em> = "as your word/promise" — grounding the petition in a prior divine commitment.</p>',
    "170": '<p>"Let my prayer (<em>tĕḥinnātî</em>) reach you — rescue me as you have promised" — <em>tĕḥinnâ</em> (H8467) = prayer for grace, supplication (from <em>ḥānan</em> = to be gracious; the petition that throws itself on divine mercy rather than merit). The parallel with v. 169: cry + prayer, reaching-before-YHWH + rescue. The final stanza doubles its appeal — the acrostic is ending; it must be heard.</p>',
    "171": '<p>"My lips will overflow (<em>tibbāʿnâ śĕpātay</em>) with praise (<em>tĕhillâ</em>), because you have taught me your <em>ḥuqqîm</em>" — <em>nābaʿ</em> (H5042) = to overflow, bubble up (like a spring); praise that overflows rather than being deliberately produced — a spontaneous abundance. Teaching Torah produces abundant praise: the connection is experiential (not logical). Having been taught the statutes, the psalmist cannot but praise. The final stanza moves toward praise even as it continues petition.</p>',
    "172": '<p>"My tongue will celebrate (<em>taʿan lĕšônî</em>) your word (<em>ʾimrātêkā</em>), for all your <em>miṣwôt</em> are right (<em>ṣedeq</em>)" — <em>ʿānâ</em> in this context = to respond, to sing antiphonally (cf. Exod 15:21 — Miriam\'s response in the Song of the Sea). The tongue "responding" to the word: the divine word calls out and the psalmist\'s tongue answers. Torah as dialogue: the word initiates, human praise responds. All the commandments are <em>ṣedeq</em> — right/just/true — the final affirmation before the closing petition.</p>',
    "173": '<p>"Be ready to help me (<em>tĕhî-yādĕkā lĕʿozrēnî</em>), for I have chosen (<em>bāḥartî</em>) your <em>piqqûdîm</em>" — the "ready hand" (<em>yāḏĕkā lĕʿāzar</em>) is the divine assistance position — YHWH\'s hand as the instrument of rescue (Exod 3:20; 6:1; Deut 26:8). The psalmist\'s choosing (<em>bāḥar</em>) of the precepts is offered as the covenant ground for the divine hand\'s readiness. The free choice of Torah creates the covenant relationship that makes divine assistance appropriate.</p>',
    "174": '<p>"I have longed (<em>tāʾaḇtî</em>) for your salvation, O LORD — your <em>tôrâ</em> is my delight (<em>šāʿăšuʿāy</em>)" — <em>tāʾaḇ</em> (H8373) = to desire intensely (a rare, strong word of longing). The intensity of longing for salvation is matched by the delight in Torah — the two are inseparable: to long for YHWH\'s salvation is to delight in his Torah, since Torah is the form his saving will takes in human life.</p>',
    "175": '<p>"Let me live (<em>tĕḥî napšî</em>) so that I may praise you (<em>wîhallelekkā</em>) — let your <em>mišpāṭîm</em> sustain me (<em>yaʿzĕrûnî</em>)" — life petitioned for the purpose of praise — not self-continuation but worship. The final purpose-clause of the psalm\'s living: to praise YHWH. The judicial ordinances (<em>mišpāṭîm</em>) as "help" — they sustain life, not merely regulate it. Divine justice is life-sustaining, not merely life-governing.</p>',
    "176": '<p>"I have wandered away (<em>tāʾîtî kĕśeh ʾōḇēd</em>) like a lost sheep — come and find me (<em>baqqēš</em>), for I have not forgotten your <em>miṣwôt</em>" — the closing verse of the entire 176-verse psalm is a confession of wandering and a plea for divine seeking. <em>Śeh ʾōḇēd</em> = "a lost sheep" — the image from which Jesus draws the parable of the lost sheep (Luke 15:4-7; Matt 18:12-14). The great Torah-psalm, after expressing the highest ideals of covenant devotion, ends with the admission that the psalmist is a lost sheep. The law reveals the gap; divine seeking closes it. Not the psalm\'s failure but its climax: honest need meeting seeking grace.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    print('Psalms 119 mkt-context written.')

if __name__ == '__main__':
    main()
